import React, { useState, useRef, useEffect } from 'react';

import '../HeaderNavigator.css';

function HeaderNavigator({
  headerNavigatorClass = "header-navigator",
  headerNavigatorItemClass = "header-navigator-item",
  headerNavigatorLinkClass = "header-navigator-link",
  headerNavigatorDropdownClass = "header-navigator-dropdown"
}) {
  const [activeTab, setActiveTab] = useState(0);
  const [highlightStyle, setHighlightStyle] = useState({});
  const navRef = useRef(null);

  const tabs = [
    { label: 'Home', href: '#home' },
    { label: 'Profile', path: '/profile' },
    { label: 'Resources', href: '#resources', dropdown: [
      { label: 'Resources', href: '#resources' },
      { label: 'Projects', href: '#projects' },
      { label: 'Repositories', href: '#repositories' }
    ]},
    { label: 'Programming Courses', href: '#programming_intro', dropdown: [
      { label: 'Courses', href: '#programming_courses' },
      { label: 'Guides', href: '#programming_guides' },
      { label: 'Manuals', href: '#programming_manuals' },
      { label: 'Books', href: '#programming_books' },
      { label: 'Official References', href: '#programming_official_references' },
      { label: 'FAQ', href: '#programming_faq' },
    ]},
    { label: 'Languages', href: '#languages_intro' },
    { label: 'Operating Systems', href: '#os_intro' },
    { label: 'Tools', href: '#tools_intro' },
    { label: 'Info', href: '#info' },
    { label: 'References', href: '#references' },
    { label: 'Contacts', href: '#contacts' },
    { label: 'About me', href: '#about_me' },
  ];

  useEffect(() => {
    if(navRef.current) {
        const tabElements = Array.from(navRef.current.children).filter(
        el => el.classList.contains(headerNavigatorItemClass)
        );
        const activeLink = tabElements[activeTab];
        if(activeLink){
        setHighlightStyle({
            width: `${activeLink.offsetWidth}px`,
            left: `${activeLink.offsetLeft}px`
        });
        }
    }
    }, [activeTab]);

  return (
    <nav className={headerNavigatorClass} ref={navRef}>
      <div className="highlight" style={highlightStyle}></div>
      {tabs.map((tab, index) => (
        <div
            key={index}
            className={`${headerNavigatorItemClass} ${activeTab === index ? 'active' : ''}`}
            onClick={() => setActiveTab(index)}
        >
            <a href={tab.href} className={headerNavigatorLinkClass}>
            {tab.label}
            </a>
            {tab.dropdown && (
            <div className={headerNavigatorDropdownClass}>
                {tab.dropdown.map((item, idx) => (
                <a key={idx} href={item.href}>{item.label}</a>
                ))}
            </div>
            )}
        </div>
        ))}
    </nav>
  );
}

export default HeaderNavigator;
